retriever_agent = Agent(
    name="retriever",
    model="gemini-2.0-flash",
    instruction="Execute retrieval from assigned sources only. Preserve source metadata."
)

@retriever_agent.tool
def pinecone_retrieve(query: str, top_k: int = 5) -> list[dict]:
    """Retrieve from Pinecone vector store."""
    results = pinecone_client.query(
        vector=embed(query),
        top_k=top_k,
        include_metadata=True
    )
    return [{
        'content': match['metadata']['text'],
        'source': match['metadata']['source'],
        'score': match['score']
    } for match in results['matches']]

retriever_agent.compile()

synthesizer_agent = Agent(
    name="synthesizer",
    model="gemini-2.0-pro",
    instruction="Synthesize from provided chunks ONLY. Use [1], [2] citation format."
)

@synthesizer_agent.tool
def format_citations(chunks: list[dict]) -> str:
    """Return numbered citation list for synthesis."""
    return "\n".join([f"[{i+1}] {chunk['source']}" for i, chunk in enumerate(chunks)])

