from google_adk import Workflow

workflow = Workflow(agents=[planner_agent, retriever_agent, synthesizer_agent])

@workflow.entrypoint
def agentic_rag(query: str):
    """Full Agentic RAG pipeline."""
    sub_queries = planner_agent.run(query)

    all_chunks = []
    for sub_query in sub_queries:
        chunks = retriever_agent.run(sub_query)
        all_chunks.extend(chunks)

    response = synthesizer_agent.run({
        'query': query,
        'chunks': all_chunks
    })

    return response

