def cycle_detection_guardrail(ctx):
    """Detect circular delegation patterns."""
    session_state = vex_client.get_session(ctx.session_id)
    recent_calls = session_state.get("agent_calls", [])[-10:]  # Last 10 calls

    # Check for cycles
    call_chain = [call["agent_name"] for call in recent_calls]
    for i in range(len(call_chain) - 3):
        if (call_chain[i] == ctx.agent.name and 
            call_chain[i+1] == call_chain[i+2] == call_chain[i+3]):
            return {
                "pass": False,
                "reason": f"Circular delegation detected: {call_chain[i:]} repeating",
                "remediation": "terminate_session"
            }

    return {"pass": True}

vex_client.register_verification(cycle_detection_guardrail, trigger="before_agent")
